   629→router.post('/practice/submit-video', authMiddleware, async (req, res) => {
   630→  try {
   631→    const { transcription, frames, duration_seconds, audio_data } = req.body;
   632→    // Ensure NOT NULL fields have safe defaults
   633→    const question_id = req.body.question_id || 'general';
   634→    const category = req.body.category || 'behavioral';
   635→    // Default question text from library if not provided
   636→    const libQ = PRACTICE_QUESTION_LIBRARY.find(q => q.id === question_id);
   637→    const question = req.body.question || (libQ && libQ.question) || `Practice question ${question_id || 'unknown'}`;
   638→
   639→    if (!transcription || transcription.trim().length < 20) {
   640→      return res.status(400).json({ error: 'Transcription too short. Please speak for at least 15-20 seconds.' });
   641→    }
   642→
   643→    if (!frames || !Array.isArray(frames) || frames.length === 0) {
   644→      return res.status(400).json({ error: 'No video frames captured. Please allow camera access.' });
   645→    }
   646→
   647→    // Look up key_points from question library
   648→    const libraryQuestion = PRACTICE_QUESTION_LIBRARY.find(q => q.id === question_id);
   649→    const keyPoints = libraryQuestion ? libraryQuestion.key_points : ['Content quality', 'Structure', 'Clarity', 'Relevance'];
   650→
   651→    // Run comprehensive multi-modal analysis (now with optional audio)
   652→    const coaching = await analyzeVideoInterviewResponse(
   653→      question,
   654→      transcription,
   655→      frames,
   656→      duration_seconds || 60,
   657→      keyPoints,
   658→      { subscriptionId: req.user.stripe_subscription_id, audioData: audio_data || null }
   659→    );
   660→
   661→    // Save practice session with video data
   662→    await pool.query(
   663→      `INSERT INTO practice_sessions
   664→       (user_id, question_id, question, category, response_text, score, coaching_data, response_type, transcription, audio_analysis, video_analysis, duration_seconds, created_at)
   665→       VALUES ($1, $2, $3, $4, $5, $6, $7, 'video', $8, $9, $10, $11, NOW())`,
   666→      [
   667→        req.user.id,
   668→        question_id,
   669→        question,
   670→        category,
   671→        transcription,
   672→        Math.round(coaching.overall_score),
   673→        JSON.stringify(coaching),
   674→        transcription,
   675→        JSON.stringify(coaching.communication),
   676→        JSON.stringify(coaching.presentation),
   677→        duration_seconds || 60
   678→      ]
   679→    );
   680→
   681→    res.json({
   682→      success: true,
   683→      coaching
   684→    });
   685→  } catch (err) {
   686→    console.error('Submit video practice response error:', err);
   687→    res.status(500).json({ error: 'Failed to analyze video response. Please try again.' });
   688→  }
   689→});
   690→
   691→// Get practice statistics
   692→router.get('/practice/stats', authMiddleware, async (req, res) => {
   693→  try {
   694→    const stats = await pool.query(
   695→      `SELECT
   696→        COUNT(*) as total_questions,
   697→        AVG(score) as average_score,
   698→        MAX(created_at) as last_practice
   699→       FROM practice_sessions
   700→       WHERE user_id = $1`,
   701→      [req.user.id]
   702→    );
   703→
   704→    // Calculate improvement (compare first half vs second half of sessions)
   705→    const improvement = await pool.query(
   706→      `WITH ordered_sessions AS (
   707→        SELECT score, ROW_NUMBER() OVER (ORDER BY created_at) as rn,
   708→               COUNT(*) OVER () as total
   709→        FROM practice_sessions
   710→        WHERE user_id = $1
   711→      )
   712→      SELECT
   713→        AVG(CASE WHEN rn <= total/2 THEN score END) as first_half_avg,
   714→        AVG(CASE WHEN rn > total/2 THEN score END) as second_half_avg
   715→      FROM ordered_sessions`,
   716→      [req.user.id]
   717→    );
   718→
   719→    let improvementPercent = null;
   720→    if (improvement.rows[0].first_half_avg && improvement.rows[0].second_half_avg) {
   721→      const firstHalf = parseFloat(improvement.rows[0].first_half_avg);
   722→      const secondHalf = parseFloat(improvement.rows[0].second_half_avg);
   723→      improvementPercent = ((secondHalf - firstHalf) / firstHalf) * 100;
   724→    }
   725→
   726→    // Calculate day streak
   727→    const streakResult = await pool.query(
   728→      `WITH RECURSIVE date_series AS (
   729→        SELECT CURRENT_DATE::date as check_date, 0 as days_back
   730→        UNION ALL
   731→        SELECT (check_date - INTERVAL '1 day')::date, days_back + 1
   732→        FROM date_series
   733→        WHERE days_back < 30
   734→      )
   735→      SELECT COUNT(*) as streak
   736→      FROM date_series d
   737→      WHERE EXISTS (
   738→        SELECT 1 FROM practice_sessions
   739→        WHERE user_id = $1 AND DATE(created_at) = d.check_date
   740→      )
   741→      AND d.check_date <= CURRENT_DATE
   742→      AND NOT EXISTS (
   743→        SELECT 1 FROM date_series d2
   744→        WHERE d2.check_date > d.check_date
   745→        AND d2.check_date <= CURRENT_DATE
   746→        AND NOT EXISTS (
   747→          SELECT 1 FROM practice_sessions
   748→          WHERE user_id = $1 AND DATE(created_at) = d2.check_date
   749→        )
   750→      )`,
   751→      [req.user.id]
   752→    );
   753→
   754→    res.json({
   755→      success: true,
   756→      stats: {
   757→        total_questions: parseInt(stats.rows[0].total_questions) || 0,
   758→        average_score: parseFloat(stats.rows[0].average_score) || null,
   759→        improvement: improvementPercent,
   760→        day_streak: parseInt(streakResult.rows[0].streak) || 0,
   761→        last_practice: stats.rows[0].last_practice
   762→      }
   763→    });
   764→  } catch (err) {
   765→    console.error('Get practice stats error:', err);
   766→    res.status(500).json({ error: 'Failed to fetch statistics' });
   767→  }
   768→});
   769→
   770→// Get practice progress dashboard
   771→router.get('/practice/progress', authMiddleware, async (req, res) => {
   772→  try {
   773→    // Progress by category
   774→    const byCategory = await pool.query(
   775→      `SELECT
   776→        category,
