  1058→    const moduleConfig = MODULE_CHAINS[options.module];
  1059→    const variant = (moduleConfig && moduleConfig.vision) || 'default';
  1060→
  1061→    return this.execute('vision', async (providerKey) => {
  1062→      let client, model;
  1063→
  1064→      switch (providerKey) {
  1065→        case 'openai_vision':
  1066→          client = this.clients.openai;
  1067→          model = 'gpt-4o';
  1068→          break;
  1069→        case 'nim_nemotron_vl':
  1070→          client = this.clients.nim;
  1071→          model = NIM_MODELS.vision_nemotron_vl;
  1072→          break;
  1073→        case 'nim_gemma_vision':
  1074→          client = this.clients.nim;
  1075→          model = NIM_MODELS.vision_gemma;
  1076→          break;
  1077→        default:
  1078→          throw new Error(`Unknown vision provider: ${providerKey}`);
  1079→      }
  1080→
  1081→      // Build content array with text + images
  1082→      const content = [{ type: 'text', text: prompt }];
  1083→      for (const url of imageUrls) {
  1084→        content.push({
  1085→          type: 'image_url',
  1086→          image_url: { url, detail: 'low' },
  1087→        });
  1088→      }
  1089→
  1090→      const params = {
  1091→        model,
  1092→        max_tokens: options.maxTokens || 2048,
  1093→        messages: [
  1094→          ...(options.system ? [{ role: 'system', content: options.system }] : []),
  1095→          { role: 'user', content },
  1096→        ],
  1097→      };
  1098→
  1099→      // Polsia proxy needs task field
  1100→      if (providerKey === 'openai_vision') params.task = options.task || 'vision-analysis';
  1101→      if (options.response_format) params.response_format = options.response_format;
  1102→
  1103→      const response = await client.chat.completions.create(params);
  1104→      const text = response.choices[0].message.content;
  1105→      // Track OpenAI vision token usage
  1106→      if (providerKey === 'openai_vision') {
  1107→        const visionTokens = (response.usage && response.usage.total_tokens)
  1108→          ? response.usage.total_tokens
  1109→          : tokenBudget.estimateVisionTokens(imageUrls.length, prompt.length);
  1110→        return { _result: text, _tokenCount: visionTokens };
  1111→      }
  1112→      return text;
  1113→    }, variant, { module: options.module || 'unknown', feature: options.feature || 'vision', userId: options.userId });
  1114→  }
