  1138→          case 'nim_magpie_multilingual':
  1139→            return this._nimMagpieTTS('nim_magpie_multilingual', text, options);
  1140→          case 'nim_magpie_flow':
  1141→            return this._nimMagpieTTS('nim_magpie_flow', text, options);
  1142→          case 'nim_magpie_zeroshot':
  1143→            return this._nimMagpieTTS('nim_magpie_zeroshot', text, options);
  1144→          case 'nim_fastpitch':
