  "common_mistake": "What mistake they made and how to avoid it",
  "practice_prompt": "A follow-up question they should practice"
}

Only return the JSON object.`;

  const result = await chat(prompt, {
    system: 'You are an expert interview coach. Be supportive, specific, and actionable. Always return valid JSON.',
    subscriptionId: options.subscriptionId,
    module: 'mock_interview', feature: 'coaching'
  });

  try {
    const parsed = JSON.parse(result);
    // BUG FIX: JSON.parse(null) and JSON.parse("null") both return null.
    // This would be a fulfilled promise with null value, bypassing allSettled fallbacks.
    if (parsed == null || typeof parsed !== 'object') {
      throw new Error('AI returned null or non-object coaching response');
    }
    return parsed;
  } catch (e) {
    // BUG FIX (Feb 14, 2026): Wrap fallback JSON.parse in its own try/catch.
    // Previously, if the regex match contained invalid JSON, the unguarded JSON.parse
    // would throw inside the catch block, propagating as an uncaught error.
    if (result && typeof result === 'string') {
      try {
        const match = result.match(/\{[\s\S]*\}/);
        if (match) {
          const extracted = JSON.parse(match[0]);
          if (extracted != null && typeof extracted === 'object') return extracted;
        }
      } catch (parseErr) {
        console.warn('[coaching] Fallback JSON extraction also failed:', parseErr.message);
      }
    }
    throw new Error('Failed to generate coaching');
  }
}

// ─── VISION ANALYSIS: Now with automatic multi-provider fallback ─────
