                ) : aiSpeaking ? (
                  <div className="h-14 w-14 rounded-full bg-violet-600/20 border-2 border-violet-400/40 flex items-center justify-center">
                    <Volume2 className="h-6 w-6 text-violet-400 animate-pulse" />
                  </div>
                ) : (
